+608     const exists = await this.prisma.companyCustomSkill.findUnique({
+609       where: {
+610         companyId_name: {
+611           companyId: BigInt(companyId),
+612           name: dto.name,
+613         },
+614       },
+615     });
+616     if (exists) {
+617       if (!exists.isActive) {
+618         // 恢复已软删除的
+619         const restored = await this.prisma.companyCustomSkill.update({
+620           where: { id: exists.id },
+621           data: { isActive: true, category: dto.category, hot: dto.hot ?? false },
+622         });
+623         return this._formatSkill(restored);
+624       }
+625       throw new BadRequestException('同名技能已存在');
+626     }
+627 
+628     const skill = await this.prisma.companyCustomSkill.create({
+629       data: {
+630         companyId: BigInt(companyId),
+631         name: dto.name,
+632         category: dto.category,
+633         hot: dto.hot ?? false,
+634       },
+635     });
+636     return this._formatSkill(skill);
