+639   async updateCustomSkill(
+640     companyId: number,
+641     skillId: number,
+642     dto: Partial<CreateCustomSkillDto>,
+643   ) {
+644     const skill = await this.prisma.companyCustomSkill.findFirst({
+645       where: {
+646         id: BigInt(skillId),
+647         companyId: BigInt(companyId),
+648         isActive: true,
+649       },
+650     });
+651     if (!skill) throw new NotFoundException('技能不存在');
+652 
+653     if (dto.name && dto.name !== skill.name) {
+654       const conflict = await this.prisma.companyCustomSkill.findUnique({
+655         where: {
+656           companyId_name: {
+657             companyId: BigInt(companyId),
+658             name: dto.name,
+659           },
+660         },
+661       });
+662       if (conflict) throw new BadRequestException('同名技能已存在');
+663     }
+664 
+665     const updated = await this.prisma.companyCustomSkill.update({
+666       where: { id: BigInt(skillId) },
+667       data: {
+668         ...(dto.name !== undefined ? { name: dto.name } : {}),
+669         ...(dto.category !== undefined ? { category: dto.category } : {}),
+670         ...(dto.hot !== undefined ? { hot: dto.hot } : {}),
+671       },
+672     });
+673     return this._formatSkill(updated);
